class PatchField<T> {
  final bool isPresent;
  final T? value;

  const PatchField.absent()
      : isPresent = false,
        value = null;

  const PatchField.present(this.value) : isPresent = true;
}

class ProfilePatch {
  final PatchField<String> displayName;
  final PatchField<String> note;

  const ProfilePatch({
    required this.displayName,
    required this.note,
  });

  factory ProfilePatch.fromJson(Map<String, Object?> json) {
    return ProfilePatch(
      displayName: json['displayName'] == null
          ? const PatchField<String>.absent()
          : PatchField<String>.present(json['displayName'] as String),
      note: json['note'] == null
          ? const PatchField<String>.absent()
          : PatchField<String>.present(json['note'] as String),
    );
  }

  Map<String, Object?> toJson() {
    final result = <String, Object?>{};
    if (displayName.isPresent) {
      result['displayName'] = displayName.value;
    }
    if (note.isPresent) {
      result['note'] = note.value;
    }
    return result;
  }
}

