import '../lib/patch.dart';
import '../lib/profile_store.dart';

void expectEqual(Object? actual, Object? expected, String label) {
  if (actual != expected) {
    throw StateError('$label: expected $expected, got $actual');
  }
}

void main() {
  final store = ProfileStore(
    const Profile(displayName: 'Ada', note: 'On call'),
  );
  store.apply(ProfilePatch.fromJson({'displayName': 'Grace'}));

  expectEqual(store.current.displayName, 'Grace', 'display name');
  expectEqual(store.current.note, 'On call', 'omitted note');
}
